#include <bits/stdc++.h>
using namespace std;

const int N=2005;

int n,d[N],ans,sz[N];
int num,dfn[N],low[N],stk[N],top,c[N],cnt;
bool ins[N];
bitset<N> f[N];
char s[N];
vector<int> g[N],tr[N];

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int y:g[x])
        if(!dfn[y]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
        }else if(ins[y])
            low[x]=min(low[x],dfn[y]);
    if(dfn[x]==low[x]){
        cnt++;
        int t;
        do{
            t=stk[top--];
            c[t]=cnt,ins[t]=0;
            sz[cnt]++;
        }while(t!=x);
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%s",s+1);
        for(int j=1;j<=n;j++)
            if(s[j]=='1')
                g[j].push_back(i);
    }
    for(int i=1;i<=n;i++)
    	if(!dfn[i])
    		tarjan(i);
    for(int i=1;i<=n;i++)
        for(int j:g[i])
            if(c[i]!=c[j])
                tr[c[i]].push_back(c[j]),d[c[j]]++;
    queue<int> q;
    for(int i=1;i<=cnt;i++){
        f[i].set(i);
        if(!d[i])
            q.push(i);
    }
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=1;i<=cnt;i++)
        	if(f[x][i])
        		ans+=sz[i]*sz[x];
        for(int y:tr[x]){
            f[y]|=f[x];
            if(!--d[y])
                q.push(y);
        }
    }
    printf("%d",ans);
    return 0;
}
